#include <stdio.h>
#include <string.h>
#define MAX 1000
void backtrack(char *L, int *protein, int k, int S, int index, char *current, int *current_protein) {
    if (*current_protein == S) {
        printf("%s\n", current);
        return;
    }
    if (index >= strlen(L)) return;
    for (int i = index; i < strlen(L); i++) {
        int ingredient = L[i] - 'a';
        if (*current_protein + protein[ingredient] <= S) {
            current[i - index] = L[i];
            *current_protein += protein[ingredient];
            backtrack(L, protein, k, S, i + 1, current, current_protein);
            *current_protein -= protein[ingredient];
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
