            scanf("%d", &protein[i]);
        }
        char L[MAX];
        scanf("%s", L);
        int S;
        scanf("%d", &S);
        char current[MAX];
        int current_protein = 0;
        backtrack(L, protein, k, S, 0, current, &current_protein);
        printf("IMPOSSIBLE\n");
    }
    return 0;
}

