import java.util.Scanner;
public class Main {
    public static void backtrack(String L, int[] protein, int k, int S, int index, StringBuilder current, int current_protein) {
        if (current_protein == S) {
            System.out.println(current);
            return;
        }
        if (index >= L.length()) return;
        for (int i = index; i < L.length(); i++) {
            int ingredient = L.charAt(i) - 'a';
            if (current_protein + protein[ingredient] <= S) {
                current.append(L.charAt(i));
                backtrack(L, protein, k, S, i + 1, current, current_protein + protein[ingredient]);
                current.deleteCharAt(current.length() - 1);
            }
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int k = scanner.nextInt();
            int[] protein = new int[26];
            for (int i = 0; i < k; i++) {
                protein[i] = scanner.nextInt();
            }
            String L = scanner.next();
            int S = scanner.nextInt();
            StringBuilder current = new StringBuilder();
            backtrack(L, protein, k, S, 0, current, 0);
            System.out.println("IMPOSSIBLE");
        }
    }
